/**
 * From https://github.com/Azure/azure-cosmosdb-js-server/blob/master/samples/stored-procedures/bulkDelete.js
 * A Cosmos DB stored procedure that bulk deletes documents for a given query.<br/>
 * Note: You may need to execute this sproc multiple times (depending whether the sproc is able to delete every document within the execution timeout limit).
 *
 * @function
 * @param {string} query - A query that provides the documents to be deleted (e.g. "SELECT c._self FROM c WHERE c.founded_year = 2008"). Note: For best performance, reduce the # of properties returned per document in the query to only what's required (e.g. prefer SELECT c._self over SELECT * )
 * @returns {Object.<number, boolean>} Returns an object with the two properties:<br/>
 *   deleted - contains a count of documents deleted<br/>
 *   continuation - a boolean whether you should execute the sproc again (true if there are more documents to delete; false otherwise).
 */
function bulkDeleteSproc(query) {
    var collection = getContext().getCollection();
    var collectionLink = collection.getSelfLink();
    var response = getContext().getResponse();
    var responseBody = {
        deleted: 0,
        continuation: true
    };

    // Validate input.
    if (!query) throw new Error("The query is undefined or null.");

    tryQueryAndDelete();

    // Recursively runs the query w/ support for continuation tokens.
    // Calls tryDelete(documents) as soon as the query returns documents.
    function tryQueryAndDelete(continuation) {
        var requestOptions = {continuation: continuation};

        var isAccepted = collection.queryDocuments(collectionLink, query, requestOptions, function (err, retrievedDocs, responseOptions) {
            if (err) throw err;

            if (retrievedDocs.length > 0) {
                // Begin deleting documents as soon as documents are returned form the query results.
                // tryDelete() resumes querying after deleting; no need to page through continuation tokens.
                //  - this is to prioritize writes over reads given timeout constraints.
                tryDelete(retrievedDocs);
            } else if (responseOptions.continuation) {
                // Else if the query came back empty, but with a continuation token; repeat the query w/ the token.
                tryQueryAndDelete(responseOptions.continuation);
            } else {
                // Else if there are no more documents and no continuation token - we are finished deleting documents.
                responseBody.continuation = false;
                response.setBody(responseBody);
            }
        });

        // If we hit execution bounds - return continuation: true.
        if (!isAccepted) {
            response.setBody(responseBody);
        }
    }

    // Recursively deletes documents passed in as an array argument.
    // Attempts to query for more on empty array.
    function tryDelete(documents) {
        if (documents.length > 0) {
            // Delete the first document in the array.
            var isAccepted = collection.deleteDocument(documents[0]._self, {}, function (err, responseOptions) {
                if (err) throw err;

                responseBody.deleted++;
                documents.shift();
                // Delete the next document in the array.
                tryDelete(documents);
            });

            // If we hit execution bounds - return continuation: true.
            if (!isAccepted) {
                response.setBody(responseBody);
            }
        } else {
            // If the document array is empty, query for more documents.
            tryQueryAndDelete();
        }
    }
}

function spSyncData(doc) {
    var collection = getContext().getCollection();
    var collectionLink = collection.getSelfLink();
    var response = getContext().getResponse();
    var removeFieldTtl = "ttl";
    if (!doc) throw new Error("Document is undefined or null.");
    if (!doc["id"]) throw new Error("The id is undefined or null.");
    var id = doc["id"];
    tryQueryAndUpdate();
    function tryQueryAndUpdate(continuation) {
        var query = { query: "select * from root r where r.id = @id", parameters: [{ name: "@id", value: id }] };
        var requestOptions = { continuation: continuation };
        var isAccepted = collection.queryDocuments(collectionLink, query, requestOptions, function (err, documents, responseOptions) {
            if (err) throw err;
            if (documents.length > 0) {
                // If the document is found, update it.
                // There is no need to check for a continuation token since we are querying for a single document.
                tryUpdate(documents[0]);
            } else if (responseOptions.continuation) {
                // Else if the query came back empty, but with a continuation token; repeat the query w/ the token.
                // It is highly unlikely for this to happen when performing a query by id; but is included to serve as an example for larger queries.
                tryQueryAndUpdate(responseOptions.continuation);
            } else {
                // Else a document with the given id does not exist..
                var isAdded = collection.createDocument(collectionLink, doc, function (err, addDocument, responseOptions) {
                    if (err) throw err;
                    // If we have successfully added the document - return it in the response body.
                    response.setBody(addDocument);
                });
            }
        });

        // If we hit execution bounds - throw an exception.
        // This is highly unlikely given that this is a query by id; but is included to serve as an example for larger queries.
        if (!isAccepted) {
            throw new Error("The stored procedure timed out.");
        }
    }
    // Updates the supplied document according to the update object passed in to the sproc.
    function tryUpdate(document) {
        var requestOptions = { etag: document._etag };
        var fields, i;
        delete document[removeFieldTtl];
        fields = Object.keys(doc);
        for (i = 0; i < fields.length; i++) {
            document[fields[i]] = doc[fields[i]];
        }
        // Update the document.
        var isAccepted = collection.replaceDocument(document._self, document, requestOptions, function (err, updatedDocument, responseOptions) {
            if (err) throw err;
            // If we have successfully updated the document - return it in the response body.
            response.setBody(updatedDocument);
        });

        // If we hit execution bounds - throw an exception.
        if (!isAccepted) {
            throw new Error("The stored procedure timed out.");
        }
    }
}

function spSyncBulkData(docs) {
    var collection = getContext().getCollection();
    var collectionLink = collection.getSelfLink();
    var count = 0;
    var doc = null;
    var removeFieldTtl = "ttl";
    if (!docs) throw new Error("The array is undefined or null.");
    if (typeof docs === "string") docs = JSON.parse(docs);
    var docsLength = docs.length;
    if (docsLength === 0) {
        getContext().getResponse().setBody(0);
        return;
    }
    tryUpsert(docs[count], callback);
    function tryUpsert(document, callback) {
        var id = document["id"];
        var query = { query: "select * from root r where r.id = @id", parameters: [{ name: "@id", value: id }] };
        var requestOptions = {};
        var isAccepted = collection.queryDocuments(collectionLink, query, requestOptions, function (err, documents, responseOptions) {
            if (err) throw err;
            if (documents.length > 0) {                
                doc = document;
                tryUpdate(documents[0]);
            } else {
                isAccepted = collection.createDocument(collectionLink, document, callback);
            }
        });
        if (!isAccepted) getContext().getResponse().setBody(count);
    }
    function tryUpdate(document) {
        var requestOptions = { etag: document._etag };
        var fields, i;
        delete document[removeFieldTtl];
        fields = Object.keys(doc);
        for (i = 0; i < fields.length; i++) {
            document[fields[i]] = doc[fields[i]];
        }
        var isAccepted = collection.replaceDocument(document._self, document, requestOptions, callback);
        if (!isAccepted) throw new Error("The stored procedure timed out.");
    }
    function callback(err, doc, options) {
        if (err) throw err;
        count++;
        if (count >= docsLength) {
            getContext().getResponse().setBody(count);
        } else {
            tryUpsert(docs[count], callback);
        }
    }
}

